import React, { useEffect, useState } from "react";
import axios from "axios";

export default function TodayDashboard() {
  const [todayFoods, setTodayFoods] = useState([]);
  const [topItems, setTopItems] = useState([]);

useEffect(() => {
  const fetchDashboard = async () => {
    const res = await axios.get('/api/dashboard/today-dashboard');
    setTodayFoods(res.data.todayFoods);
    setTopItems(res.data.topSelling);
  };
  fetchDashboard();
}, []);


  const fetchTodayFoods = async () => {
    const res = await axios.get("/api/foods/today"); // backend returns only today’s menu
    setTodayFoods(res.data);
  };

  const fetchTopItems = async () => {
    const res = await axios.get("/api/orders/top-items"); // backend returns top-selling items today
    setTopItems(res.data);
  };

  return (
    <div className="min-h-screen bg-slate-50 p-6">
      <div className="max-w-6xl mx-auto">
        <h1 className="text-2xl font-bold mb-6">Today's Dashboard</h1>

        {/* Today's Menu */}
        <section className="bg-white p-4 rounded-lg shadow mb-6">
          <h2 className="text-xl font-semibold mb-3">Today's Menu</h2>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {todayFoods.map(food => (
              <div key={food._id} className="border rounded p-3 flex flex-col items-center">
                {food.img && <img src={`/uploads/${food.img}`} alt={food.name} className="w-24 h-24 object-cover rounded mb-2" />}
                <div className="font-medium">{food.name}</div>
                <div className="text-sm text-gray-500">₹{food.price}</div>
              </div>
            ))}
            {todayFoods.length === 0 && <div className="text-gray-500">No foods marked for today.</div>}
          </div>
        </section>

        {/* Top Selling Items */}
        <section className="bg-white p-4 rounded-lg shadow">
          <h2 className="text-xl font-semibold mb-3">Top Selling Items</h2>
          <ul className="space-y-2">
            {topItems.map((item, index) => (
              <li key={index} className="flex justify-between border p-2 rounded">
                <span>{item.foodName}</span>
                <span className="font-medium">{item.totalSold} sold</span>
              </li>
            ))}
            {topItems.length === 0 && <div className="text-gray-500">No sales data for today yet.</div>}
          </ul>
        </section>
      </div>
    </div>
  );
}
